3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveKeys = new Set(liveCells.map(keyOf));
16	  const candidates = new Map<string, Cell>();
17	  const counts = new Map<string, number>();
18	
19	  for (const cell of liveCells.flatMap(neighborsOf)) {
20	    const k = keyOf(cell);
21	    candidates.set(k, cell);
22	    counts.set(k, (counts.get(k) ?? 0) + 1);
23	  }
24	
25	  const survives = (k: string, count: number): boolean =>
26	    count === 3 || (count === 2 && liveKeys.has(k));
27	
28	  return Array.from(counts)
29	    .filter(([k, count]) => survives(k, count))
30	    .map(([k]) => candidates.get(k)!);
31	}
