export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(keyOf));
  const neighborhood = new Map<string, { cell: Cell; count: number }>();

  for (const cell of liveCells.flatMap(neighborsOf)) {
    const k = keyOf(cell);
    const prev = neighborhood.get(k);
    neighborhood.set(k, { cell, count: (prev?.count ?? 0) + 1 });
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(k));

  return Array.from(neighborhood.values())
    .filter(({ cell, count }) => survives(keyOf(cell), count))
    .map(({ cell }) => cell);
}

